    let input_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_INPUT_BYTE_WEI) * U256::from(input_len as u64);
    let output_component =
        U256::from(HTTP_EXECUTOR_FEE_PER_OUTPUT_BYTE_WEI) * U256::from(output_len as u64);
